using ModelContextProtocol.Server;
using System.ComponentModel;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Reverses the input string.")]
    public static string Reverse(
        [Description("The string to reverse")] string input)
    {
        var chars = input.ToCharArray();
        Array.Reverse(chars);
        return new string(chars);
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { EnableLogging = true, EnableMetrics = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status", Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns the current server status including uptime.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "healthy",
            StartedAt = Program.StartedAt,
            Uptime = (DateTime.UtcNow - Program.StartedAt).ToString()
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

